function r_and_d_quarterly_progress_app_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('r_and_d_quarterly_progress_app');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic r_and_d_lookup if passed as filterer
	if(Request::val('filterer_r_and_d_lookup')) {
		$_REQUEST['r_and_d_lookup'] = Request::val('filterer_r_and_d_lookup');
	}

	$data = [
		'date' => Request::dateComponents('date', '1'),
		'attendees' => br2nl(Request::val('attendees', '')),
		'minutes' => br2nl(Request::val('minutes', '')),
		'Tech_Mgr_Remarks' => br2nl(Request::val('Tech_Mgr_Remarks', '')),
		'ceo_remarks' => br2nl(Request::val('ceo_remarks', '')),
		'pd_remarks' => br2nl(Request::val('pd_remarks', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];


	// automatic r_and_d_lookup if passed as filterer
	if(Request::val('filterer_r_and_d_lookup')) {
		$data['r_and_d_lookup'] = Request::val('filterer_r_and_d_lookup');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('r_and_d_quarterly_progress_app', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		r_and_d_quarterly_progress_app_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function r_and_d_quarterly_progress_app_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function r_and_d_quarterly_progress_app_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('r_and_d_quarterly_progress_app', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: r_and_d_quarterly_progress_app_before_delete
	if(function_exists('r_and_d_quarterly_progress_app_before_delete')) {
		$args = [];
		if(!r_and_d_quarterly_progress_app_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `r_and_d_quarterly_progress_app` WHERE `id`='{$selected_id}'", $eo);

	// hook: r_and_d_quarterly_progress_app_after_delete
	if(function_exists('r_and_d_quarterly_progress_app_after_delete')) {
		$args = [];
		r_and_d_quarterly_progress_app_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='r_and_d_quarterly_progress_app' AND `pkValue`='{$selected_id}'", $eo);
}

function r_and_d_quarterly_progress_app_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('r_and_d_quarterly_progress_app', $selected_id, 'edit')) return false;

	$data = [
		'date' => Request::dateComponents('date', ''),
		'attendees' => br2nl(Request::val('attendees', '')),
		'minutes' => br2nl(Request::val('minutes', '')),
		'Tech_Mgr_Remarks' => br2nl(Request::val('Tech_Mgr_Remarks', '')),
		'ceo_remarks' => br2nl(Request::val('ceo_remarks', '')),
		'pd_remarks' => br2nl(Request::val('pd_remarks', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('r_and_d_quarterly_progress_app', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: r_and_d_quarterly_progress_app_before_update
	if(function_exists('r_and_d_quarterly_progress_app_before_update')) {
		$args = ['old_data' => $old_data];
		if(!r_and_d_quarterly_progress_app_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'r_and_d_quarterly_progress_app',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="r_and_d_quarterly_progress_app_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('r_and_d_quarterly_progress_app', $data['selectedID'], calculated_fields()['r_and_d_quarterly_progress_app']);

	// hook: r_and_d_quarterly_progress_app_after_update
	if(function_exists('r_and_d_quarterly_progress_app_after_update')) {
		if($row = getRecord('r_and_d_quarterly_progress_app', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!r_and_d_quarterly_progress_app_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('r_and_d_quarterly_progress_app', $selected_id);
}

