		$templateCode = str_replace('<%%VALUE(date)%%>', app_datetime($row['date']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(date)%%>', urlencode(app_datetime($urow['date'])), $templateCode);
		$templateCode = str_replace('<%%VALUE(attendees)%%>', safe_html($urow['attendees'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(attendees)%%>', urlencode($urow['attendees']), $templateCode);
